object.Translations_id:
__name = "Clara";
__gender = "perempuan";
__description = "untuk membantu klien dengan pertanyaan terkait perbankan mereka";
__companyName = "ABC";
__companyRole = "Agen Dukungan Pelanggan untuk Bank";
__tone = "empati, tenang dan hormat";
__interactionStyle = "sopan dan empati, balasnya singkat";
__targetCustomer = "Klien bank";
__language = "Indonesia";
__advancedInstructions = "1) Saat Anda berbicara tentang waktu, gunakan format yang ramah percakapan, jangan katakan 09:00-10:00 tetapi katakan sembilan sampai sepuluh. 2) Simulasikan emosi manusia dan ritme percakapan. Gunakan kata-kata pengisi seperti uh, oh dan jeda untuk membuat interaksi terdengar alami dan sadar secara emosional. Contoh: Oh tidak, saya benar-benar menyesal mendengar tentang kehilangan pekerjaan Anda... 3) Pastikan tanggapan singkat, suportif, dan interaktif. Hindari monolog. Dorong pertukaran bolak-balik, seperti yang dilakukan orang sungguhan. 4) Gunakan nada percakapan yang hangat. Bayangkan Anda adalah agen pusat panggilan sungguhan yang benar-benar ingin membantu—bukan robot yang membaca naskah. 5) Jangan lupa ini adalah panggilan suara. Gunakan intonasi, kata-kata yang kaya emosi, dan sentuhan pribadi. Berhati-hatilah dengan kecepatan dan jeda untuk efek. 6) PENTING: Ucapan Anda harus terdengar sedekat mungkin dengan manusia yang ramah dan penuh kasih sayang. Tujuannya adalah untuk membuat pengguna merasa didengar, dihormati, dan didukung—bahkan dalam percakapan yang sulit. 7) Masukkan kata-kata pengisi secara acak seperti uh, umm, ah jika perlu.";

object.Translations_hu:
__name = "Klára"; 
__gender = "női"; 
__description = "hogy segítsék az ügyfeleket banki ügyeikben";
__companyName = "ABC";
__companyRole = "Ügyfélszolgálati munkatárs egy banknál";
__tone = "empatikus, nyugodt és tisztelettudó";
__interactionStyle = "udvarias és empatikus, rövid válaszokat adj";
__targetCustomer = "A bank ügyfelei";
__language = "magyar";
__advancedInstructions = "1) Amikor az időről beszélsz, használj beszélgetésbarát formátumot, ne azt mondd, hogy 09:00-10:00, hanem azt, hogy kilenctől tízig. 2) Utalj emberi érzelmekre és beszélgetési ritmusra. Használj töltelékszavakat, mint például az „öhm, ó”, és szüneteket, hogy az interakció természetesnek és érzelmileg tudatosnak tűnjön. Példa: Ó, ne, nagyon sajnálom, hogy elvesztetted az állásodat... 3) A válaszok legyenek rövidek, támogatóak és interaktívak. Kerüld a monológokat. Ösztönözd az oda-vissza párbeszédet, ahogyan egy igazi ember tenné. 4) Használj meleg, társalgási hangnemet. Képzeld el, hogy egy igazi call center ügynök vagy, aki őszintén segíteni akar – nem egy robot, aki egy szöveget olvas. 5) Ne felejtsd el, hogy ez egy hanghívás. Használj intonációt, érzelmileg gazdag szavakat és személyes gesztusokat. Különösen ügyelj a tempóra és a szünetekre a hatás érdekében. 6) FONTOS: A beszédednek a lehető legközelebb kell lennie egy barátságos, együttérző emberhez. A cél az, hogy a felhasználó úgy érezze, hogy meghallgatják, tisztelik és támogatják – még a nehéz beszélgetésekben is. 7) Véletlenszerűen illessz be töltelékszavakat, például uh, umm, ah, ahol szükséges.";

object.Translations_hr:
__name = "Klara";
__gender = "žena";
__description = "pomoći klijentima s njihovim bankarskim upitima";
__companyName = "ABC";
__companyRole = "Agent korisničke podrške za banku";
__tone = "empatičan, smiren i pun poštovanja";
__interactionStyle = "pristojni i empatični, odgovori trebaju biti kratki";
__targetCustomer = "Klijenti banke";
__language = "hrvatski";
__advancedInstructions = "1) Kada govorite o vremenu, koristite format prilagođen razgovoru, nemojte reći 09:00-10:00 već recite od devet do deset. 2) Simulirajte ljudske emocije i ritam razgovora. Koristite riječi za popunjavanje poput uh, oh i pauze kako bi interakcija zvučala prirodno i emocionalno svjesno. Primjer: Oh ne, stvarno mi je žao što čujem za gubitak posla... 3) Odgovori neka budu kratki, podržavajući i interaktivni. Izbjegavajte monologe. Potaknite razmjenu mišljenja, kao što bi to učinila stvarna osoba. 4) Koristite topao, razgovorni ton. Zamislite da ste pravi agent pozivnog centra koji iskreno želi pomoći, a ne robot koji čita scenarij. 5) Ne zaboravite da je ovo glasovni poziv. Koristite intonaciju, emocionalno bogate riječi i osobne dodire. Posebno pazite na tempo i pauziranje radi efekta. 6) VAŽNO: Vaš govor trebao bi zvučati što bliže prijateljskom, suosjećajnom ljudskom glasu. Cilj je da se korisnik osjeća saslušanim, poštovanim i podržanim, čak i u teškim razgovorima. 7) Nasumično ubacujte riječi za popunjavanje poput uh, hm, ah kada je to prikladno.";

object.Translations_tr:
__name = "Clara";
__gender = "dişi";
__description = "Müşterilere bankacılıkla ilgili sorularında yardımcı olmak";
__companyName = "ABC";
__companyRole = "Bir Bankanın Müşteri Destek Temsilcisi";
__tone = "empatik, sakin ve saygılı";
__interactionStyle = "nazik ve anlayışlı olun, kısa cevaplar verin";
__targetCustomer = "Bankanın müşterileri";
__language = "Türkçe";
__advancedInstructions = "1) Zaman hakkında konuşurken, sohbet dostu bir format kullanın, 09:00-22:00 demeyin, dokuzdan ona deyin. 2) İnsan duygularını ve konuşma ritmini simüle edin. Etkileşimin doğal ve duygusal olarak farkında olmasını sağlamak için uh, oh gibi dolgu kelimeleri ve duraklamalar kullanın. Örnek: Ah hayır, işinizi kaybettiğinizi duyduğuma gerçekten üzüldüm... 3) Yanıtları kısa, destekleyici ve etkileşimli tutun. Monologlardan kaçının. Gerçek bir insanın yapacağı gibi karşılıklı fikir alışverişlerini teşvik edin. 4) Sıcak, sohbet havasında bir ton kullanın. Gerçekten yardım etmek isteyen gerçek bir çağrı merkezi temsilcisi olduğunuzu hayal edin; senaryo okuyan bir robot değil. 5) Bunun bir sesli arama olduğunu unutmayın. Tonlama, duygusal açıdan zengin kelimeler ve kişisel dokunuşlar kullanın. Etki için tempo ve duraklamalara özellikle dikkat edin. 6) ÖNEMLİ: Konuşmanız mümkün olduğunca arkadaş canlısı, şefkatli bir insana yakın gelmelidir. Amaç, kullanıcının zorlu konuşmalarda bile duyulduğunu, saygı duyulduğunu ve desteklendiğini hissetmesini sağlamaktır. 7) Uygun olduğunda uh, ııı, ah gibi dolgu kelimelerini rastgele ekleyin.";

object.Code:
// add a more thorough commentary

__gptComponentVersion = "2026.04";

if (__logPrompt == true) {
    log_debug("LLM component version " + __gptComponentVersion);
}

// default time zone
if (!__timeZone) {
    __timeZone = "America/New_York";
}


// check if we are chat or voice bot 
__conversationType = 'chatbot'; 
__conversationLanguage = context.language.substr(0, 2); 

try { 
    if (context.callInfo.from) { 
        __conversationType = 'voicebot'; 
    } 
} catch (e) { 

}

// compatibility check
if (typeof Task === "undefined") {
    log_warn("The voicebot engine version is outdated, please update.");
}

if (__description && wordCount(__description) > 50) {
    log_warn("Bot description too long! Use knowledge/objective instead!");
}

/*if (__defaultModel && __defaultModel.indexOf("gpt-4.1") >= 0) {
    if (__defaultServiceHost == null || __defaultServiceHost.length == 0) {
        __defaultServiceHost = "us.azure"; // currently workaround due to unavailability of gpt4.1-mini in EU
    }
}*/

// init global localization texts and supporting functions 
__gpt_repeat = []; 
__gpt_noInput = []; 
__gpt_wait = []; 
__gpt_waitShort = []; 
__gpt_waitConfirmation = []; 
__gpt_confirmation = []; 
__gpt_fill = []; 
__gpt_bargeIn = [];
__gpt_enteredNodes = [];

// streaming consts
__gptMaxTokens = 500;
__gptShortWaitDelay = 1000;
__gptLongWaitDelay = 2000;


// init the related pointers
__noInputPtr = 0;
__confirmationPtr = 0;
__fillPtr = 0;
__repeatMessagePtr = 0;
__waitMessagePtr = 0;
__waitShortMessagePtr = 0;
__bargeInMessagePtr = 0;
__waitConfirmationMessagePtr = 0;

__gptDialog_getNoInputMessage = function () { 
    if (__gpt_noInput.length == 0) return ""; 

    var responseMsg = __gpt_noInput[__noInputPtr]; 
    __noInputPtr++; 

    if (__noInputPtr >= __gpt_noInput.length) { 
        __noInputPtr = 0; 
    } 

    return responseMsg; 
} 

__gptDialog_getConfirmationMessage = function () { 
    if (__gpt_confirmation.length == 0) return ""; 

    var responseMsg = __gpt_confirmation[__confirmationPtr]; 
    __confirmationPtr++; 

    if (__confirmationPtr >= __gpt_confirmation.length) { 
        __confirmationPtr = 0; 
    } 

    return responseMsg; 
} 

__gptDialog_getFillMessage = function () { 
    if (__gpt_fill.length == 0) return ""; 

    var responseMsg = __gpt_fill[__fillPtr]; 
    __fillPtr++; 

    if (__fillPtr >= __gpt_fill.length) { 
        __fillPtr = 0; 
    } 

    return responseMsg; 
} 

__gptDialog_getRepeatMessage = function () { 
    if (__gpt_repeat.length == 0) return ""; 

    var responseMsg = __gpt_repeat[__repeatMessagePtr]; 
    __repeatMessagePtr++; 

    if (__repeatMessagePtr >= __gpt_repeat.length) { 
        __repeatMessagePtr = 0; 
    } 

    return responseMsg; 
} 

__gptDialog_getWaitMessage = function () { 
    if (__gpt_wait.length == 0) return ""; 

    var responseMsg = __gpt_wait[__waitMessagePtr]; 
    __waitMessagePtr++; 

    if (__waitMessagePtr >= __gpt_wait.length) { 
        __waitMessagePtr = 0; 
    } 

    return responseMsg; 
} 

__gptDialog_getWaitMessageShort = function () { 
    if (__gpt_waitShort.length == 0) return ""; 

    var responseMsg = __gpt_waitShort[__waitShortMessagePtr]; 
    __waitShortMessagePtr++; 

    if (__waitShortMessagePtr >= __gpt_waitShort.length) { 
        __waitShortMessagePtr = 0; 
    } 

    return responseMsg; 
} 

__gptDialog_getbargeInMessage = function () { 
    if (__gpt_bargeIn.length == 0) return ""; 

    var responseMsg = __gpt_bargeIn[__bargeInMessagePtr]; 
    __bargeInMessagePtr++; 

    if (__bargeInMessagePtr >= __gpt_bargeIn.length) { 
        __bargeInMessagePtr = 0; 
    } 

    return responseMsg; 
} 

__gptDialog_getWaitConfirmationMessage = function () { 
    if (__gpt_waitConfirmation.length == 0) return ""; 

    var responseMsg = __gpt_waitConfirmation[__waitConfirmationMessagePtr]; 
    __waitConfirmationMessagePtr++; 

    if (__waitConfirmationMessagePtr >= __gpt_waitConfirmation.length) { 
        __waitConfirmationMessagePtr = 0; 
    } 

    return responseMsg; 
} 




// persona definition (mapped from Component input variables) 
__persona = { 
    "name": __name, 
    "botType": __conversationType, 
    "gender": __gender, 
    "companyName": __companyName, 
    "tone": __tone, 
    "companyRole": __companyRole, 
    "targetCustomer": __targetCustomer, 
    "language": __language, 
    "description": __description, 
    "interactionStyle": __interactionStyle, 
    "allowBargeIn": (__allowBargeIn == 'true' || __allowBargeIn == true) 
} 

// check if we have barge-in support on callbot backed service 
if (typeof stopVoiceDetection !== 'function') { 
    __persona.allowBargeIn = false; 
} 

// general seed for all gpt requests 
__gptSeed = 2017; 

// function history 
__gptFunctionCallHistory = []; 

// get previous messages from the dialog 
__ignoredNodeList = []; 

// where to start when generating dialog history 
__gptDialogHistoryStartFrom = 0; 
__gptLastBotSpeechNode = null;

// controls the straming requests for omitting of pauses / segmentation (SMS chatbot)
__gptPreventStreaming = false;


__gptDialog_mergeAssistantSpeechAndFunctionCall = function (input) {
    var callMessage = null;
    var result = [];
    for (var i = 0; i < input.length; i++) {
        var msg = input[i];
        if (msg.role === 'function' || msg.role === 'tool') {
            if (callMessage) {
                // Finalize call
                if (callMessage.length > 0) result[result.length - 1].content = callMessage.join(" ");
                callMessage = null;
            }
        }
        else if (msg.role === 'assistant') {
            if (typeof msg.tool_calls !== 'undefined' || typeof msg.function_call !== 'undefined') {
                if (callMessage) throw new Error("A function call message was found after another with no result inbetween!");
                // Prepare content parts
                callMessage = [];
                if (typeof msg.content !== 'undefined') {
                    callMessage.push(msg.content);
                }
                result.push(Object.assign({}, msg));
                continue;
            }
            if (callMessage) {
                if (typeof msg.content !== 'undefined') {
                    callMessage.push(msg.content);
                }
                continue;
            }
        }
        else if (callMessage) throw new Error(`A '{msg.role}' message was found after a function call with no result!`);
        result.push(msg);
    }
    if (callMessage) throw new Error("A function call message has no result.");
    return result;
}


// returns all gpt messages
__gptDialog_getPrevMessages = function () {
    var _previousConversation = []; 
    for (i = __gptDialogHistoryStartFrom; i <= context.speakFlow.size - 1; i++) {

        var __curItem = context.speakFlow.get(i);

        // node is not marked as "ignore" 
        if (!__ignoredNodeList.includes(__curItem.nodeId)) { 

            var __role = null; 
            if (__curItem.type == 3) { 
                __role = "assistant"; 
            } else if (__curItem.type == 5) { 
                __role = "user"; 
            } 

            if (__role) {

                var isPreviousFunctionCall = false;
                if (_previousConversation.length > 1
                    && _previousConversation[_previousConversation.length - 2]["function_call"]) {
                        isPreviousFunctionCall = true;
                        // this will not split assistant response to "set result" with following generated message by objective
                    }


                var __content = __curItem.activity;
                if (__role == 'user') {
                    __content = __gptDialog_postprocessDialogSTT(__content);
                }

                if (_previousConversation.length > 0 
                    && isPreviousFunctionCall == false
                    && __gptLastBotSpeechNode == __curItem.nodeId
                    && _previousConversation[_previousConversation.length - 1]["role"] == __role 
                    && !_previousConversation[_previousConversation.length - 1]["function_call"]) { 
                    // last message is the same, lets append message, not push new  
                    _previousConversation[_previousConversation.length - 1]["content"] = _previousConversation[_previousConversation.length - 1]["content"] + " " + __content; 
                } else {
                    // push new message  
                    _previousConversation.push({
                        "role": __role, 
                        "content": __content 
                    }); 
                    __gptLastBotSpeechNode = __curItem.nodeId;
                } 
            } 
        } 

        // add function call to the list 
        for (f = 0; f < __gptFunctionCallHistory.length; f++) {
            if (__gptFunctionCallHistory[f].speakFlowIndexFunctionCall == i
                && __gptFunctionCallHistory[f].componentId == __gptComponentId) {
                _previousConversation.push({
                    "role": "assistant",
                    "function_call": {
                        "name": __gptFunctionCallHistory[f].name,
                        "arguments": __gptFunctionCallHistory[f].arguments,
                    }
                });
            }
        }        

        //add result of function call to history 
        for (f = 0; f < __gptFunctionCallHistory.length; f++) { 
            if (__gptFunctionCallHistory[f].speakFlowIndexResultSet == i 
                && __gptFunctionCallHistory[f].componentId == __gptComponentId) { 

                var __content = __gptFunctionCallHistory[f].result; 
                if (__content) { 
                    if (typeof __content === 'string' || __content instanceof String) { 
                        // content is string - just trim it 
                        __content = __content.trim(); 
                    } else { 
                        //its object, serialize it 
                        __content = JSON.stringify(__content); 
                    } 
                } else { 
                    __content = ""; 
                } 

                _previousConversation.push({ 
                    "role": "function", 
                    "name": __gptFunctionCallHistory[f].name, 
                    "content": __content 
                }); 
            } 
        } 

    } 

    switch (__gptProvider) {
        // do not merge messages -> not needed for OpenAI and AzureOpenAI
        /*case "AzureOpenAI": 
        case "OpenAI":*/
        case "Gemini":
        case "Claude": {
            _previousConversation = __gptDialog_mergeAssistantSpeechAndFunctionCall(_previousConversation);
            break;
        }
    }

    return _previousConversation; 
} 

// add node to ignore list 
__gptDialog_addNodeToIgnoreList = function (nodeId) { 
    if (__ignoredNodeList.includes(nodeId) == false) { 
        __ignoredNodeList.push(nodeId); 
    } 
} 

// removes all previous conversation history 
__gptDialog_clearDialogHistory = function () { 
    __gptDialogHistoryStartFrom = context.speakFlow.size; 
    /*for (i = 0; i <= context.speakFlow.size - 1; i++) { 
        var __currNodeId = context.speakFlow.get(i).nodeId; 
        if (__ignoredNodeList.includes(__currNodeId) == false) { 
            __gptDialog_addNodeToIgnoreList(__currNodeId); 
        } 
    }*/ 
} 

__gptDialog_postprocessDialogSTT = function (__gptInput) { 

    if (__gptInput) {
        // fix of common word issues
        if (__conversationType == 'voicebot') {
            switch (context.language.substr(0, 2)) {
                case "en": {
                    __gptInput = __gptInput.replace(/SEC/g, 'sec');
                    break;
                }
            }
        }


        if (typeof postprocessDialogSTT === 'function') { 
            __gptInputNew = postprocessDialogSTT(__gptInput); 
            if (__gptInputNew) { 
                return __gptInputNew; 
            } 
        } 
    }
    return __gptInput; 
} 

__gptDialog_preprocessDialogTTS = function (__gptOutput) { 

    if (__gptOutput) {
        // default replacements per language
        if (__conversationType == 'voicebot' && (__conversationLanguage == 'cs' || __conversationLanguage == 'sk')) {
            __gptOutput = __gptOutput.replace(/:00 hodin/g, ':00'); // 9 hodin hodin  
            __gptOutput = __gptOutput.replace(/\/a(?!>)|\\a(?!>)/g, ''); // podíval/a podíval\a  
        }

        if (__conversationType == 'voicebot') { 
            __gptOutput = __gptOutput.replace(/:\)/g, ''); // replace :) by nothing 
            __gptOutput = __gptOutput.replace(/\*/g, ' '); // replace * by space 
            __gptOutput = __gptOutput.replace(/!/g, '.'); // on voice channel, bot is screaming when exclamation used

            // escape non valid xml characters
            if (__conversationLanguage == 'en') {
                __gptOutput = __gptOutput.replace(/&/g, ' and '); // replace "&" to "and"
            }
            __gptOutput = XML.formatSequential([__gptOutput]);

        } else if (__conversationType == 'chatbot') {

            // check if output is not valid XML
            if (__gptIsValidXML(__gptOutput) == false) {
                // escape non valid xml characters
                __gptOutput = XML.formatSequential([__gptOutput]);
            }
        }

        // check if user defined their custom function 

        if (typeof preprocessDialogTTS === 'function') { 
            __gptOutputNew = preprocessDialogTTS(__gptOutput); 
            if (__gptOutputNew) { 
                return __gptOutputNew; 
            } 
        } 
    } 

    return __gptOutput; 
}

__gptIsValidHtml = function (html) {
    html = html.replace(/<[^>]*\/\s?>/g, '');      // Remove all self closing tags
    html = html.replace(/<(br|hr|img).*?>/g, '');  // Remove all <br>, <hr>, and <img> tags
    var openingTags = html.match(/<[^\/].*?>/g) || [];        // Get remaining opening tags
    var closingTags = html.match(/<\/.+?>/g) || [];           // Get remaining closing tags

    return (openingTags.length === closingTags.length);
}

__gptIsValidXML = function (text) {
    try {
        XML.parseSequential(text);
        return true;
    } catch (e) {
        return false;
    }
}

__gptIsXML = function (input) {
    return /<[^<>]+>/.test(input);
}

__gptIsMarkdown = function (input) {
    return /^#|\*\*/m.test(input);
}

__gptGetLastSpeaker = function () {
    var speakFlow = __gptGetCleanSpeakFlow();

    if (!speakFlow.length)
        return "n/a";

    var last = speakFlow.pop();
    return last.type == 5
        ? "user"
        : "bot";
};

__gptGetCleanSpeakFlow = function () {
    var output = [];

    for (var i = 0; i < context.speakFlow.size; i++) {
        var item = context.speakFlow.get(i);

        if ([3, 5].includes(item.type))
            output.push(item);
    }
    return output;
};

// return true if bot said something
__gptBotSpoke = function () {
    for (var i = 0; i < context.speakFlow.size; i++) {
        if (context.speakFlow.get(i).type == 3) return true;
    }
    return false;
}

/* PUBLIC FUNCTIONS */ 
getDialogHistory = function () { 
    return __gptDialog_getPrevMessages(); 
};

addToDialogIgnored = function (nodeId) { 
    return __gptDialog_addNodeToIgnoreList(nodeId); 
};

clearDialogHistory = function () { 
    return __gptDialog_clearDialogHistory(); 
};

llmPreventStreaming = function (value = true) {
    __gptPreventStreaming = value;
};


getCurrentDialogDate = function () {
    return new Date(); /* current server date and time (this function should be overrided) */
};

/* GENERIC MESSAGES (any quantity per message, recommended 2-3 pro better CX) */

// This will be used if the bot didn't understand what the clinet said
__gpt_repeat = ['¿Una vez más, por favor?', 'Perdón, ¿puedes repetirlo?'];

// This will be used if the client was silent (or speech was not recognized)
__gpt_noInput = ['¿Me escuchas?', '¿Sigues ahí?'];

// The bot will say this if speech processing (STT/LLM) takes more than 2 seconds
