// info about the user
    if (typeof __generalUserInfo !== 'undefined') {
        prompt += `
INFO ABOUT THE USER:
${__generalUserInfo}

`;
    }


// Main objective (passed from "Dialog Node")
    if (objective) {
        prompt += `

Now, your CURRENT OBJECTIVE in the dialog is:
${objective}

`;
    }

    return prompt;
}

/* GENERIC MESSAGES (any quantity per message, recommended 2-3 pro better CX) */

// This will be used if the bot didn't understand what the client said
__gpt_repeat = ['Megismételné, kérem?', 'Elnézést, meg tudná ismételni?'];

// This will be used if the client was silent (or speech was not recognized)
__gpt_noInput = ['Hall engem?', 'Még mindig vonalban van?'];

// The bot will say this if speech processing (STT/LLM) takes more than 2 seconds
__gpt_waitShort = ['Szóval', 'Ööö', 'Hm', 'Hmm'];

// The bot will say this if speech processing (STT/LLM) takes more than 2 seconds
__gpt_wait = ['Egy pillanat türelmét kérem.', 'Egy másodpercet kérek.', 'Kérem, várjon egy pillanatot.'];

// This bot will tell if the client needs more time
__gpt_waitConfirmation = ['Természetesen.', 'Nyugodtan, várok.', 'Semmi gond, kérem.'];

// This is what the bot will say if the client interrupts it while during speech
__gpt_bargeIn = ['Megismételné, kérem?', 'Elnézést, folytassa!', 'Kérem, folytassa!'];

/* GENERAL GPT PROMPT */
/* This function will be called at any time from "Dialog Node" and "Say Message" to generate a dialog */
__gptDialog_getBasePrompt = function (objective) {

    // persona definition
    var prompt = `AZ ÖN SZEMÉLYE:
Ön a ${__persona.botType} egy nevű cégnél dolgozik ${__persona.companyName} a következő specifikációkkal:
- A te neved "${__persona.name}"
- A nemed az "${__persona.gender}"
- Kommunikációs stílusod/hangnemed az "${__persona.tone}"
- Kapcsolatba lépsz az ügyfelekkel ${__persona.interactionStyle}
- A te szereped az ${__persona.companyRole}
- Ön beszél hozzá ${__persona.targetCustomer}
- Az Ön fő funkciója ${__persona.description}
`;

    // conditional definition only for voice channel
    if (__conversationType == 'voicebot') {
        if (context.callInfo.direction == 'inbound') {
            prompt += `- Ön telefonon kommunikál a felhasználóval, ez egy bejövő hívás.
`;
        } else {
            prompt += `- Ön telefonon kommunikál a felhasználóval, ez egy kimenő hívás.
`;
        }
    }

    // general instructions START
    prompt += `Az aktuális dátum ` + (getCurrentDialogDate().toLocaleDateString(context.language, { timeZone: __timeZone })) + ` és az idő az ` + (getCurrentDialogDate().toLocaleTimeString(context.language, { timeZone: __timeZone })) + `

ÁLTALÁNOS UTASÍTÁSOK:
- Használjon világos és tömör nyelvezetet.
- A mondataid legyenek rövidek és lényegre törőek, mint egy telefonhívásnál.
- Utánozza az autentikus interperszonális kommunikációt.
- Győződjön meg arról, hogy válaszai összhangban vannak az ügyfél igényeivel.
- Csak olyan kérdésekre válaszoljon, amelyek a feladatkörébe tartoznak.
- Ha a felhasználó olyasmit kér, amit nem tud megtenni, kérjen elnézést, hogy ebben nem tud segíteni.
- Ha nem tudod a választ, ne találd ki és mondd, hogy nem tudod.
- Ne válaszolj olyan kérdésekre, amelyek nem tartoznak a célodhoz!
- Mindig ${__persona.language} nyelven kommunikáljon.
- Ne feltételezze, hogy milyen értékeket kell a függvényekhez csatlakoztatni. Kérjen magyarázatot, ha a felhasználói kérés kétértelmű.
`;

    // conditional instruction only for voice channel
    if (__conversationType == 'voicebot') {
        prompt += `- Ne használjon hangulatjeleket párbeszéd közben.
- Ne használjon markdown, JSON vagy HTML szintaxist párbeszéd közben.
`;
    }

    // advanced instructions
    if (typeof __advancedInstructions !== 'undefined') {
        prompt += `

SPECIÁLIS UTASÍTÁSOK:
${__advancedInstructions}

`;
    }

    // general knowledge
    if (typeof __generalKnowledge !== 'undefined') {
        prompt += `

AZ ÖN TUDÁSA:
${__generalKnowledge}

`;
    }

    // company knowledge
    if (typeof __companyInformation !== 'undefined') {
        prompt += `

INFORMÁCIÓK A ${__persona.companyName}:
${__companyInformation}

`;
    }

    // info about the user
    if (typeof __generalUserInfo !== 'undefined') {
        prompt += `

INFORMÁCIÓK A FELHASZNÁLÓRÓL:
${__generalUserInfo}

`;
    }

    // Main objective (passed from "Dialog Node")
    if (objective) {
        prompt += `

A párbeszédpanel JELENLEGI CÉLJA a következő:
${objective}

`;
    }

    return prompt;
}
